body:
I attempted to define the functionality of a virtual interface within a class. The values appear to be functioning correctly, but they don’t seem to be reflected in the waveform. It’s quite puzzling. Could you please investigate?

`timescale 1ns/100ps

interface test_if(
  input   [31:0] isig,
  output  [31:0] osig
);

endinterface


class CTest;
  virtual test_if vif;

  function new(virtual test_if vif);
    this.vif = vif;
  endfunction


  function void set_output(int d);
    vif.osig = d;
  endfunction

endclass


module top();

  // VCD or FST Dump
  initial begin
    $dumpfile("wave.dump");
    $dumpvars(0, top);
  end

