  logic [31:0] isig, osig;

  test_if   vif1(.isig, .osig);

  event Ev_test;

  CTest test_obj;
  initial begin
    test_obj = new( .vif(vif1) );

    #1;
    test_obj.set_output(123);
    ->Ev_test;
    $display("Check:  osig = %d", osig );

    #10;
    $display("");
    $finish;
  end

endmodule 
